import { createSlice } from '@reduxjs/toolkit';

const initialState = {
  customer: null,
  token: localStorage.getItem('customerToken') || null,
  accountNumber: null,
  SBAccountNumber: null,
  loading: false,
  error: null,
  isAuthenticated: !!localStorage.getItem('customerToken'),
};

const authSlice = createSlice({
  name: 'auth',
  initialState,
  reducers: {
    loginRequest: (state) => {
      state.loading = true;
      state.error = null;
    },
    loginSuccess: (state, action) => {
      state.loading = false;
      state.customer = action.payload.customer;
      state.token = action.payload.token;
      state.accountNumber = action.payload.accountNumber;
      state.SBAccountNumber = action.payload.SBAccountNumber;
      state.isAuthenticated = true;
      localStorage.setItem('customerToken', action.payload.token);
    },
    loginFailure: (state, action) => {
      state.loading = false;
      state.error = action.payload;
    },
    registerRequest: (state) => {
      state.loading = true;
      state.error = null;
    },
    registerSuccess: (state, action) => {
      state.loading = false;
      state.customer = action.payload.customer;
      state.token = action.payload.token;
      state.accountNumber = action.payload.accountNumber;
      state.SBAccountNumber = action.payload.SBAccountNumber;
      state.isAuthenticated = true;
      localStorage.setItem('customerToken', action.payload.token);
    },
    registerFailure: (state, action) => {
      state.loading = false;
      state.error = action.payload;
    },
    checkPhoneRequest: (state) => {
      state.loading = true;
    },
    checkPhoneSuccess: (state) => {
      state.loading = false;
    },
    checkPhoneFailure: (state, action) => {
      state.loading = false;
      state.error = action.payload;
    },
    logout: (state) => {
      state.customer = null;
      state.token = null;
      state.accountNumber = null;
      state.SBAccountNumber = null;
      state.isAuthenticated = false;
      localStorage.removeItem('customerToken');
    },
    clearError: (state) => {
      state.error = null;
    },
  },
});

export const {
  loginRequest,
  loginSuccess,
  loginFailure,
  registerRequest,
  registerSuccess,
  registerFailure,
  checkPhoneRequest,
  checkPhoneSuccess,
  checkPhoneFailure,
  logout,
  clearError,
} = authSlice.actions;

export default authSlice.reducer;
